 37â†’public class ParameterListWrappingRule :
 38â†’    StandardRule(
 39â†’        id = "parameter-list-wrapping",
 40â†’        usesEditorConfigProperties =
 41â†’            setOf(
 42â†’                CODE_STYLE_PROPERTY,
 43â†’                INDENT_SIZE_PROPERTY,
 44â†’                INDENT_STYLE_PROPERTY,
 45â†’                MAX_LINE_LENGTH_PROPERTY,
 46â†’            ),
 47â†’    ) {
 48â†’    private var codeStyle = CODE_STYLE_PROPERTY.defaultValue
 49â†’    private var indentConfig = IndentConfig.DEFAULT_INDENT_CONFIG
 50â†’    private var maxLineLength = MAX_LINE_LENGTH_PROPERTY.defaultValue
