 52â†’    override fun beforeFirstNode(editorConfig: EditorConfig) {
 53â†’        codeStyle = editorConfig[CODE_STYLE_PROPERTY]
 54â†’        maxLineLength = editorConfig[MAX_LINE_LENGTH_PROPERTY]
 55â†’        indentConfig =
 56â†’            IndentConfig(
 57â†’                indentStyle = editorConfig[INDENT_STYLE_PROPERTY],
 58â†’                tabWidth = editorConfig[INDENT_SIZE_PROPERTY],
 59â†’            )
 60â†’        if (indentConfig.disabled) {
 61â†’            stopTraversalOfAST()
 62â†’        }
