 64â†’
 65â†’    override fun beforeVisitChildNodes(
 66â†’        node: ASTNode,
 67â†’        autoCorrect: Boolean,
 68â†’        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 69â†’    ) {
 70â†’        when (node.elementType) {
 71â†’            NULLABLE_TYPE -> wrapNullableType(node, emit, autoCorrect)
 72â†’            VALUE_PARAMETER_LIST -> {
 73â†’                if (node.needToWrapParameterList()) {
 74â†’                    wrapParameterList(node, emit, autoCorrect)
 75â†’                }
 76â†’            }
 77â†’        }
 78â†’    }
