 80â†’    private fun wrapNullableType(
 81â†’        node: ASTNode,
 82â†’        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 83â†’        autoCorrect: Boolean,
 84â†’    ) {
 85â†’        require(node.elementType == NULLABLE_TYPE)
 86â†’        node
 87â†’            .takeUnless {
 88â†’                // skip when max line length is not exceedd
 89â†’                (node.column - 1 + node.textLength) <= maxLineLength
 90â†’            }?.findChildByType(FUNCTION_TYPE)
 91â†’            ?.findChildByType(VALUE_PARAMETER_LIST)
 92â†’            ?.takeIf { it.findChildByType(VALUE_PARAMETER) != null }
 93â†’            ?.takeUnless { it.textContains('\n') }
 94â†’            ?.let {
 95â†’                node
 96â†’                    .children()
 97â†’                    .forEach {
 98â†’                        when (it.elementType) {
 99â†’                            LPAR -> {
100â†’                                emit(
101â†’                                    it.startOffset,
102â†’                                    "Parameter of nullable type should be on a separate line (unless the type fits on a single line)",
103â†’                                    true,
104â†’                                )
105â†’                                if (autoCorrect) {
106â†’                                    it.upsertWhitespaceAfterMe("\n${indentConfig.indent}")
107â†’                                }
108â†’                            }
109â†’                            RPAR -> {
110â†’                                emit(it.startOffset, errorMessage(it), true)
111â†’                                if (autoCorrect) {
112â†’                                    it.upsertWhitespaceBeforeMe("\n")
113â†’                                }
114â†’                            }
115â†’                        }
116â†’                    }
117â†’            }
118â†’    }
