121â†’        when {
122â†’            hasNoParameters() -> false
123â†’            isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle() -> false
124â†’            isFunctionTypeWrappedInNullableType() -> false
125â†’            textContains('\n') -> true
126â†’            codeStyle == ktlint_official && containsAnnotatedParameter() -> true
