160â†’        node: ASTNode,
161â†’        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
162â†’        autoCorrect: Boolean,
163â†’    ) {
164â†’        val newIndentLevel = getNewIndentLevel(node)
165â†’        node
166â†’            .children()
167â†’            .forEach { child -> wrapParameterInList(newIndentLevel, child, emit, autoCorrect) }
168â†’    }
