170â†’    private fun getNewIndentLevel(node: ASTNode): Int {
171â†’        val currentIndentLevel = indentConfig.indentLevelFrom(node.indent(false))
172â†’        return when {
173â†’            // IDEA quirk:
174â†’            // fun <
175â†’            //     T,
176â†’            //     R> test(
177â†’            //     param1: T
178â†’            //     param2: R
179â†’            // )
180â†’            // instead of
181â†’            // fun <
182â†’            //     T,
183â†’            //     R> test(
184â†’            //         param1: T
185â†’            //         param2: R
186â†’            //     )
187â†’            currentIndentLevel > 0 && node.hasTypeParameterListInFront() -> currentIndentLevel - 1
188â†’
189â†’            else -> currentIndentLevel
190â†’        }
191â†’    }
