193â†’    private fun wrapParameterInList(
194â†’        newIndentLevel: Int,
195â†’        child: ASTNode,
196â†’        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
197â†’        autoCorrect: Boolean,
198â†’    ) {
199â†’        val indent = "\n" + indentConfig.indent.repeat(newIndentLevel)
200â†’        when (child.elementType) {
201â†’            LPAR -> {
202â†’                val prevLeaf = child.prevLeaf()
203â†’                if (prevLeaf is PsiWhiteSpace && prevLeaf.textContains('\n')) {
204â†’                    emit(child.startOffset, errorMessage(child), true)
205â†’                    if (autoCorrect) {
206â†’                        prevLeaf.delete()
207â†’                    }
208â†’                }
209â†’            }
210â†’            VALUE_PARAMETER,
211â†’            RPAR,
212â†’            -> {
213â†’                // aiming for
214â†’                // ... LPAR
215â†’                // <line indent + indentSize> VALUE_PARAMETER...
216â†’                // <line indent> RPAR
217â†’                val intendedIndent =
218â†’                    if (child.elementType == VALUE_PARAMETER) {
219â†’                        indent + indentConfig.indent
220â†’                    } else {
221â†’                        indent
222â†’                    }
223â†’                val prevLeaf = child.prevLeaf()
224â†’                if (prevLeaf is PsiWhiteSpace) {
225â†’                    if (prevLeaf.getText().contains("\n")) {
226â†’                        // The current child is already wrapped to a new line. Checking and fixing the
227â†’                        // correct size of the indent is the responsibility of the IndentationRule.
228â†’                        return
229â†’                    } else {
230â†’                        // The current child needs to be wrapped to a newline.
231â†’                        emit(child.startOffset, errorMessage(child), true)
232â†’                        if (autoCorrect) {
233â†’                            // The indentation is purely based on the previous leaf only. Note that in
234â†’                            // autoCorrect mode the indent rule, if enabled, runs after this rule and
235â†’                            // determines the final indentation. But if the indent rule is disabled then the
236â†’                            // indent of this rule is kept.
237â†’                            (prevLeaf as LeafPsiElement).rawReplaceWithText(intendedIndent)
238â†’                        }
239â†’                    }
240â†’                } else {
241â†’                    // Insert a new whitespace element in order to wrap the current child to a new line.
242â†’                    emit(child.startOffset, errorMessage(child), true)
243â†’                    if (autoCorrect) {
244â†’                        child.treeParent.addChild(PsiWhiteSpaceImpl(intendedIndent), child)
245â†’                    }
246â†’                }
247â†’                // Indentation of child nodes need to be fixed by the IndentationRule.
248â†’            }
249â†’        }
250â†’    }
