252â†’    private fun ASTNode.exceedsMaxLineLength() = (column - 1 + textLength) > maxLineLength && !textContains('\n')
253â†’
254â†’    private fun errorMessage(node: ASTNode) =
255â†’        when (node.elementType) {
256â†’            LPAR -> """Unnecessary newline before "(""""
257â†’            VALUE_PARAMETER ->
258â†’                "Parameter should start on a newline"
259â†’            RPAR -> """Missing newline before ")""""
260â†’            else -> throw UnsupportedOperationException()
261â†’        }
