263â†’    private fun ASTNode.hasTypeParameterListInFront(): Boolean {
264â†’        val parent = this.treeParent
265â†’        val typeParameterList =
266â†’            if (parent.elementType == PRIMARY_CONSTRUCTOR) {
267â†’                parent.prevSibling { it.elementType == TYPE_PARAMETER_LIST }
268â†’            } else {
269â†’                parent.children().firstOrNull { it.elementType == TYPE_PARAMETER_LIST }
270â†’            }
271â†’        val typeListNode =
272â†’            typeParameterList
273â†’                ?: parent.psi.collectDescendantsOfType<KtTypeArgumentList>().firstOrNull()?.node
274â†’                ?: return false
275â†’        return typeListNode.children().any { it.isWhiteSpaceWithNewline() }
276â†’    }
277â†’}
